import React, { useState, useEffect } from 'react';
import { loginUser } from '../services/api';
import { useAuth } from '../context/AuthContext';

const STARS = Array.from({ length: 80 }, (_, i) => ({
  id: i,
  top:      Math.random() * 100,
  left:     Math.random() * 100,
  size:     Math.random() * 2 + 0.5,
  duration: Math.random() * 3 + 2,
  delay:    Math.random() * 4,
}));

function Login() {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');
  const [loading, setLoading]   = useState(false);
  const [focused, setFocused]   = useState('');
  const [owlBlink, setOwlBlink] = useState(false);

  const { login } = useAuth();

  // Owl blinks every 3 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setOwlBlink(true);
      setTimeout(() => setOwlBlink(false), 200);
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      const res = await loginUser({ email, password });
      login(res.data.token, res.data.user);
      window.location.href = '/dashboard';
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={s.page}>

      {/* Stars */}
      <div style={s.stars}>
        {STARS.map(star => (
          <div key={star.id} style={{
            position: 'absolute',
            top: `${star.top}%`, left: `${star.left}%`,
            width: `${star.size}px`, height: `${star.size}px`,
            background: '#ffffff', borderRadius: '50%',
            animation: `twinkle ${star.duration}s ease-in-out infinite`,
            animationDelay: `${star.delay}s`,
            opacity: 0,
          }} />
        ))}
      </div>

      {/* Glow blobs */}
      <div style={{ position:'fixed', top:'-150px', left:'-100px', width:'500px', height:'500px', background:'radial-gradient(circle, rgba(34,197,94,0.07) 0%, transparent 70%)', pointerEvents:'none', zIndex:0 }} />
      <div style={{ position:'fixed', bottom:'-150px', right:'-100px', width:'400px', height:'400px', background:'radial-gradient(circle, rgba(99,102,241,0.06) 0%, transparent 70%)', pointerEvents:'none', zIndex:0 }} />

      {/* Left Panel */}
      <div style={s.left}>
        
        {/* Animated Owl */}
        <div style={s.owlWrap}>
          <svg width="120" height="140" viewBox="0 0 120 140" style={{ animation: 'owlFloat 3s ease-in-out infinite' }}>
            {/* Body */}
            <ellipse cx="60" cy="105" rx="32" ry="37" fill="#1a2810"/>
            <ellipse cx="60" cy="112" rx="21" ry="24" fill="#e8d5a0"/>
            {/* Wings */}
            <path d="M28,95 Q8,75 12,108 Q22,122 44,115Z" fill="#162410"/>
            <path d="M92,95 Q112,75 108,108 Q98,122 76,115Z" fill="#162410"/>
            {/* Head */}
            <circle cx="60" cy="58" r="36" fill="#1a2810"/>
            {/* Ears */}
            <polygon points="42,28 34,8 50,24" fill="#162410"/>
            <polygon points="78,28 86,8 70,24" fill="#162410"/>
            {/* Eyes */}
            <circle cx="44" cy="55" r="15" fill="#f0e4c0"/>
            <circle cx="44" cy="55" r="11" fill="#f59e0b"/>
            <circle cx="44" cy="55" r="7" fill="#111"/>
            <circle cx="47" cy="52" r="2.5" fill="white" opacity="0.9"/>
            {owlBlink && <rect x="29" y="41" width="30" height="28" rx="14" fill="#1a2810"/>}
            
            <circle cx="76" cy="55" r="15" fill="#f0e4c0"/>
            <circle cx="76" cy="55" r="11" fill="#f59e0b"/>
            <circle cx="76" cy="55" r="7" fill="#111"/>
            <circle cx="79" cy="52" r="2.5" fill="white" opacity="0.9"/>
            {owlBlink && <rect x="61" y="41" width="30" height="28" rx="14" fill="#1a2810"/>}
            
            {/* Beak */}
            <polygon points="60,68 52,80 68,80" fill="#e07820"/>
            {/* Feet */}
            <rect x="38" y="133" width="18" height="5" rx="2.5" fill="#4a2e1a"/>
            <path d="M40,133 L35,140 M44,133 L42,140 M48,133 L52,140" stroke="#2d4a20" strokeWidth="2" strokeLinecap="round" fill="none"/>
            <rect x="64" y="133" width="18" height="5" rx="2.5" fill="#4a2e1a"/>
            <path d="M66,133 L61,140 M70,133 L68,140 M74,133 L78,140" stroke="#2d4a20" strokeWidth="2" strokeLinecap="round" fill="none"/>
          </svg>
        </div>

        {/* Branding */}
        <div style={s.brand}>
          <span style={s.brandName}>Dev<span style={s.brandAccent}>Nest</span></span>
          <span style={s.betaBadge}>BETA</span>
        </div>

        {/* Hero text */}
        <h1 style={s.headline}>
          Your career.<br/>
          <span style={s.highlight}>Engineered.</span>
        </h1>
        <p style={s.subtext}>
          Stop grinding blindly. One platform for DSA tracking,
          GitHub analytics, and AI-powered interview prep.
        </p>

        {/* Stats */}
        <div style={s.statsRow}>
          {[
            { num: '25+', label: 'Problems' },
            { num: 'AI',  label: 'Mentor'   },
            { num: '∞',   label: 'Free'     },
          ].map(stat => (
            <div key={stat.label} style={s.statBox}>
              <div style={s.statNum}>{stat.num}</div>
              <div style={s.statLabel}>{stat.label}</div>
            </div>
          ))}
        </div>

        {/* Features */}
        <div style={s.features}>
          {[
            { icon: '📊', text: 'DSA Tracker — Striver, Blind 75'         },
            { icon: '🐙', text: 'GitHub Analytics — Repos & Heatmap'      },
            { icon: '🤖', text: 'AI Mentor — Personalized roadmap'        },
            { icon: '🎯', text: 'Interview Readiness Score per company'   },
          ].map(f => (
            <div key={f.text} style={s.featureRow}>
              <span style={s.featureIcon}>{f.icon}</span>
              <span style={s.featureText}>{f.text}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Right Panel */}
      <div style={s.right}>
        <div style={s.card}>
          <div style={s.cardGlow}/>
          
          <h2 style={s.cardTitle}>Welcome back 👋</h2>
          <p style={s.cardSub}>Login to continue your journey</p>

          {error && (
            <div style={s.errorBox}>⚠️ {error}</div>
          )}

          <form onSubmit={handleSubmit}>
            <div style={s.field}>
              <label style={s.label}>EMAIL ADDRESS</label>
              <div style={{ ...s.inputWrap, borderColor: focused === 'email' ? '#22c55e' : '#2a2a2a' }}>
                <span style={s.inputIcon}>✉️</span>
                <input
                  style={s.input}
                  type="email"
                  placeholder="shrey@gmail.com"
                  value={email}
                  onChange={e => setEmail(e.target.value)}
                  onFocus={() => setFocused('email')}
                  onBlur={() => setFocused('')}
                  required
                />
              </div>
            </div>

            <div style={s.field}>
              <label style={s.label}>PASSWORD</label>
              <div style={{ ...s.inputWrap, borderColor: focused === 'password' ? '#22c55e' : '#2a2a2a' }}>
                <span style={s.inputIcon}>🔒</span>
                <input
                  style={s.input}
                  type="password"
                  placeholder="••••••••"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  onFocus={() => setFocused('password')}
                  onBlur={() => setFocused('')}
                  required
                />
              </div>
            </div>

            <button
              type="submit"
              style={{ ...s.btn, opacity: loading ? 0.75 : 1 }}
              disabled={loading}
            >
              {loading ? 'Signing in...' : 'Continue to DevNest →'}
            </button>
          </form>

          <div style={s.divider}>
            <div style={s.divLine}/><span style={s.divText}>or</span><div style={s.divLine}/>
          </div>

          <p style={s.bottomText}>
            New here?{' '}
            <a href="/register" style={s.link}>Create free account</a>
          </p>
        </div>
      </div>

      <style>{`
        @keyframes twinkle {
          0%,100%{opacity:0;transform:scale(0.5)}
          50%{opacity:0.8;transform:scale(1)}
        }
        @keyframes owlFloat {
          0%,100%{transform:translateY(0px)}
          50%{transform:translateY(-12px)}
        }
        input::placeholder { color: #4b5563; }
        input:focus { outline: none; }
      `}</style>
    </div>
  );
}

const s = {
  page: {
    display: 'flex',
    minHeight: '100vh',
    background: '#080808',
    fontFamily: "'Poppins', sans-serif",
    position: 'relative',
    overflow: 'hidden',
  },
  stars: {
    position: 'fixed', top:0, left:0,
    width:'100%', height:'100%',
    pointerEvents:'none', zIndex:0,
  },
